import { useState } from "react";
import { initializeApp } from "firebase/app";
import { getAuth, createUserWithEmailAndPassword } from "firebase/auth";
import { doc, setDoc } from "firebase/firestore";
import { db, firebaseConfig } from "../firebase";
import Sidebar from "../components/Sidebar";

export default function CreateUser() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("agent");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const handleCreateUser = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    try {
      const secondaryApp = initializeApp(firebaseConfig, "Secondary");
      const secondaryAuth = getAuth(secondaryApp);
      const userCredential = await createUserWithEmailAndPassword(secondaryAuth, email, password);
      const newUser = userCredential.user;

      await setDoc(doc(db, "users", newUser.uid), {
        name: name,
        email: email,
        role: role,
        createdAt: new Date().toISOString()
      });

      await secondaryAuth.signOut();

      setMessage(`Successfully created account for ${name} (${role})!`);
      setName("");
      setEmail("");
      setPassword("");
      setRole("agent");
    } catch (err) {
      console.error(err);
      setError("Failed to create user. Make sure the password is at least 6 characters.");
    }
  };

  return (
    <div className="min-h-screen bg-[#eef4fb] flex">
      <Sidebar />

      <div className="flex-1 ml-[268px] p-8">
        <div className="max-w-2xl mx-auto">
          <header className="mb-8">
            <h1 className="text-3xl font-extrabold text-[#122033] tracking-tight">Team Management</h1>
            <p className="text-[#64748b] mt-2">Generate a new portal account and assign their role.</p>
          </header>

          <div className="bg-white p-8 rounded-[20px] shadow-sm border border-[#dbe7f3]">
            {message && <div className="bg-[#eff6ff] border border-[#bfdbfe] text-[#1e3a8a] p-4 rounded-[14px] mb-6 font-semibold">{message}</div>}
            {error && <div className="bg-[#fff1f2] border border-[#fecdd3] text-[#9f1239] p-4 rounded-[14px] mb-6 font-semibold">{error}</div>}

            <form onSubmit={handleCreateUser} className="space-y-5">
              <div>
                <label className="block text-[0.9rem] font-extrabold text-[#0a0e2f] mb-1.5">Full Name</label>
                <input type="text" value={name} onChange={(e) => setName(e.target.value)} required className="w-full p-3 border border-[#dfe7f0] rounded-[10px] focus:ring-4 focus:ring-blue-500/10 focus:border-[#bfd7f6] outline-none font-semibold text-[#0a0e2f] transition-all" />
              </div>
              <div>
                <label className="block text-[0.9rem] font-extrabold text-[#0a0e2f] mb-1.5">Email Address</label>
                <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required className="w-full p-3 border border-[#dfe7f0] rounded-[10px] focus:ring-4 focus:ring-blue-500/10 focus:border-[#bfd7f6] outline-none font-semibold text-[#0a0e2f] transition-all" />
              </div>
              <div>
                <label className="block text-[0.9rem] font-extrabold text-[#0a0e2f] mb-1.5">Temporary Password</label>
                <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required className="w-full p-3 border border-[#dfe7f0] rounded-[10px] focus:ring-4 focus:ring-blue-500/10 focus:border-[#bfd7f6] outline-none font-semibold text-[#0a0e2f] transition-all" />
              </div>
              <div>
                <label className="block text-[0.9rem] font-extrabold text-[#0a0e2f] mb-1.5">System Role</label>
                <select value={role} onChange={(e) => setRole(e.target.value)} className="w-full p-3 border border-[#dfe7f0] rounded-[10px] focus:ring-4 focus:ring-blue-500/10 focus:border-[#bfd7f6] outline-none font-semibold text-[#0a0e2f] transition-all bg-white">
                  <option value="agent">Agent</option>
                  <option value="quality_supervisor">Quality Supervisor</option>
                  <option value="team_lead">Team Lead</option>
                </select>
              </div>
              <button type="submit" className="w-full mt-4 min-h-[46px] bg-gradient-to-br from-[#172044] to-[#0a0e2f] text-white font-extrabold py-3 px-4 rounded-[14px] shadow-[0_10px_22px_rgba(10,14,47,0.18)] hover:translate-y-[-1px] hover:shadow-[0_14px_28px_rgba(10,14,47,0.22)] transition-all">
                Create Account
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}
